    @exception_handler
    @validate
    def search(
        self,
        query: Annotated[str, OpenBBField(description="Search query.")] = "",
        is_symbol: Annotated[bool, OpenBBField(description="Whether to search by ticker symbol.")] = False,
        provider: Annotated[
            Optional[Literal["cboe", "nasdaq", "sec", "tmx"]],
            OpenBBField(
                description=(
                    "The provider to use, by default None. If None, the"
                    "priority list configured in the settings is used."
                    "Default priority: cboe, nasdaq, sec, tmx."
                )
            ),
        ] = None,
        **kwargs
    ) -> OBBject:
        """Search for stock symbol, CIK, LEI, or company name.

        Parameters
        ----------
        provider : str
            The provider to use, by default None. If None, the priority list configured in the settings is used. Default priority: cboe, nasdaq, sec, tmx.
        query : str
            Search query.
        is_symbol : bool
            Whether to search by ticker symbol.
        use_cache : bool
            (provider: cboe, sec)
                Whether to use the cache or not.

            (provider: tmx)
                Whether to use a cached request. The list of companies is cached for two days.
        is_etf : bool
            If True, returns only ETFs. (provider: nasdaq)
        is_fund : bool
            Whether to direct the search to the list of mutual funds and ETFs. (provider: sec)

        Returns
        -------
        OBBject
            results : list[EquitySearch]
                Serializable results.
            provider : Optional[str]
                Provider name.
            warnings : Optional[list[Warning_]]
                list of warnings.
            chart : Optional[Chart]
                Chart object.
            extra : dict[str, Any]
                Extra info.

        EquitySearch
        ------------
        symbol : str | None
            Symbol representing the entity requested in the data.
        name : str | None
            Name of the company.
        dpm_name : str | None
            Name of the primary market maker. (provider: cboe)
        post_station : str | None
            Post and station location on the CBOE trading floor. (provider: cboe)
        nasdaq_traded : str | None
            Is Nasdaq traded? (provider: nasdaq)
        exchange : str | None
            Primary Exchange (provider: nasdaq)
        market_category : str | None
            Market Category (provider: nasdaq)
        etf : str | None
            Is ETF? (provider: nasdaq)
        round_lot_size : float | None
            Round Lot Size (provider: nasdaq)
        test_issue : str | None
            Is test Issue? (provider: nasdaq)
        financial_status : str | None
            Financial Status (provider: nasdaq)
        cqs_symbol : str | None
            CQS Symbol (provider: nasdaq)
        nasdaq_symbol : str | None
            NASDAQ Symbol (provider: nasdaq)
        next_shares : str | None
            Is NextShares? (provider: nasdaq)
        cik : str | None
            Central Index Key (provider: sec)

        Examples
        --------
        >>> from openbb import obb
        >>> obb.equity.search()
        >>> obb.equity.search(query='AAPL', is_symbol=False, use_cache=True)

        """  # noqa: E501 # pylint: disable=line-too-long

        return self._run(
            "/equity/search",
            **filter_inputs(
                provider_choices={
                    "provider": self._get_provider(
                        provider,
                        "equity.search",
                        ("cboe", "nasdaq", "sec", "tmx"),
                    )
                },
                standard_params={
                    "query": query,
                    "is_symbol": is_symbol,
                },
                extra_params=kwargs,
            )
        )

    @property
    def shorts(self):
        """Router for /equity/shorts."""
        from . import equity_shorts

        return equity_shorts.ROUTER_equity_shorts(command_runner=self._command_runner)
